Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory with the full middleware pipeline but no real network port.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### If your server uses SSE transport

```csharp
[Fact]
public async Task Sse_StreamsMessages()
{
    using var sse = await _client.GetStreamAsync("/sse");
    using var reader = new StreamReader(sse);

    // Read the endpoint event
    var line = await reader.ReadLineAsync(); // "event: endpoint"
    var data = await reader.ReadLineAsync(); // "data: /messages?sessionId=..."

    Assert.StartsWith("event: endpoint", line);

    // Now POST JSON-RPC to the advertised endpoint
    var uri = data!.Replace("data: ", "");
    var init = new { jsonrpc = "2.0", id = 1, method = "initialize", /* ... */ };
    await _client.PostAsJsonAsync(uri, init);

    // Read the SSE response lines
    await reader.ReadLineAsync(); // blank
    var eventLine = await reader.ReadLineAsync();
    var dataLine = await reader.ReadLineAsync();
    Assert.StartsWith("data:", dataLine);
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` |
| **Full pipeline** | Middleware, DI, routing all run exactly as in production |
| **Swap services** | Override `ConfigureWebHost` to replace DB/external deps with fakes |
| **`Program` visibility** | Add `<InternalsVisibleTo Include="YourTestProject" />` or a partial class if `Program` is inaccessible |

This gives you fast, deterministic tests that exercise the real MCP JSON-RPC handling end-to-end.
